function t(i){if(!i)return"-";const e=new Date(i);return isNaN(e.getTime())?(console.error("Invalid date:",i),"-"):e.toLocaleString("zh-CN",{timeZone:"Asia/Shanghai",year:"numeric",month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit",second:"2-digit",hour12:!1})}function n(i){if(!i)return"-";const e=new Date(i);return isNaN(e.getTime())?"-":e.toLocaleTimeString("zh-CN",{timeZone:"Asia/Shanghai",hour:"2-digit",minute:"2-digit",second:"2-digit",hour12:!1})}export{t as a,n as f};
